        { kr: "산책", rom: "San-chaek", en: "Walk", tip: "How to say a leisurely journey on foot, typically for pleasure or health in Korean?", situation: "Use this when you go for a walk outside.", forms: { casual: "산책 (San-chaek)", polite: "산책이에요 (San-chaek-i-e-yo)" }, examples: [{ kr: "산책을 해요.", en: "I go for a walk.", rom: "San-chaek-eul hae-yo." }, { kr: "공원을 산책해요.", en: "I walk in the park.", rom: "Gong-won-eul san-chaek-hae-yo." }, { kr: "산책이 좋아요.", en: "I like walking.", rom: "San-chaek-i jo-a-yo." }] },
        { kr: "서핑", rom: "Seo-ping", en: "Surfing", tip: "How to refer to the sport of riding on the crest or along the tunnel of a wave on a board in Korean?", situation: "Use this at the beach.", forms: { casual: "서핑 (Seo-ping)", polite: "서핑이에요 (Seo-ping-i-e-yo)" }, examples: [{ kr: "서핑을 해요.", en: "I go surfing.", rom: "Seo-ping-eul hae-yo." }, { kr: "서핑을 배우고 싶어요.", en: "I want to learn surfing.", rom: "Seo-ping-eul bae-u-go sip-eo-yo." }, { kr: "서핑이 정말 재밌어요.", en: "Surfing is really fun.", rom: "Seo-ping-i jeong-mal jae-miss-eo-yo." }] },
        { kr: "캠핑", rom: "Kaem-ping", en: "Camping", tip: "How to say the activity of spending a vacation living in a tent or specialized vehicle in Korean?", situation: "Use this during your camping trip.", forms: { casual: "캠핑 (Kaem-ping)", polite: "캠핑이에요 (Kaem-ping-i-e-yo)" }, examples: [{ kr: "캠핑을 가요.", en: "I go camping.", rom: "Kaem-ping-eul ga-yo." }, { kr: "캠핑장에서 자요.", en: "I sleep at the campsite.", rom: "Kaem-ping-jang-e-seo ja-yo." }, { kr: "캠핑이 즐거워요.", en: "Camping is enjoyable.", rom: "Kaem-ping-i jeul-geo-wo-yo." }] },
        { kr: "연주", rom: "Yeon-ju", en: "Performance", tip: "How to refer to the act of playing a musical instrument in Korean?", situation: "Use this when performing music.", forms: { casual: "연주 (Yeon-ju)", polite: "연주예요 (Yeon-ju-ye-yo)" }, examples: [{ kr: "연주를 해요.", en: "I perform music.", rom: "Yeon-ju-reul hae-yo." }, { kr: "연주가 완벽해요.", en: "The performance is perfect.", rom: "Yeon-ju-ga wan-byeok-hae-yo." }, { kr: "연주를 들으러 가요.", en: "I go to listen to a performance.", rom: "Yeon-ju-reul deul-eu-reo ga-yo." }] },
        { kr: "수집", rom: "Su-jip", en: "Collection", tip: "How to say the hobby of gathering and keeping items of a particular type, like stamps or coins, in Korean?", situation: "Use this when showing off your collection.", forms: { casual: "수집 (Su-jip)", polite: "수집이에요 (Su-jip-i-e-yo)" }, examples: [{ kr: "취미가 수집이에요.", en: "My hobby is collecting.", rom: "Chwi-mi-ga su-jip-i-e-yo." }, { kr: "우표를 수집해요.", en: "I collect stamps.", rom: "U-pyo-reul su-jip-hae-yo." }, { kr: "수집하는 것을 좋아해요.", en: "I like collecting things.", rom: "Su-jip-ha-neun geos-eul jo-ah-hae-yo." }] },
        { kr: "정원", rom: "Jeong-won", en: "Garden", tip: "How to refer to a piece of ground, often near a house, used for growing flowers, fruit, or vegetables in Korean?", situation: "Use this when gardening.", forms: { casual: "정원 (Jeong-won)", polite: "정원이에요 (Jeong-won-i-e-yo)" }, examples: [{ kr: "정원을 가꿔요.", en: "I take care of the garden.", rom: "Jeong-won-eul ga-kkwo-yo." }, { kr: "정원에 꽃이 많아요.", en: "There are many flowers in the garden.", rom: "Jeong-won-e kkot-i man-a-yo." }, { kr: "정원에서 일해요.", en: "I work in the garden.", rom: "Jeong-won-e-seo il-hae-yo." }] },
        { kr: "재배", rom: "Jae-bae", en: "Cultivation", tip: "How to say the act of growing plants or crops for food or beauty in Korean?", situation: "Use this when talking about farming.", forms: { casual: "재배 (Jae-bae)", polite: "재배예요 (Jae-bae-ye-yo)" }, examples: [{ kr: "식물을 재배해요.", en: "I cultivate plants.", rom: "Sik-mul-eul jae-bae-hae-yo." }, { kr: "토마토를 재배해요.", en: "I grow tomatoes.", rom: "To-ma-to-reul jae-bae-hae-yo." }, { kr: "재배가 힘들어요.", en: "Cultivation is hard.", rom: "Jae-bae-ga him-deul-eo-yo." }] },
        { kr: "공연", rom: "Gong-yeon", en: "Performance", tip: "How to refer to a public presentation of a play, concert, or other entertainment in Korean?", situation: "Use this when going to a show.", forms: { casual: "공연 (Gong-yeon)", polite: "공연이에요 (Gong-yeon-i-e-yo)" }, examples: [{ kr: "공연을 봐요.", en: "I watch a performance.", rom: "Gong-yeon-eul bwa-yo." }, { kr: "공연이 시작됐어요.", en: "The performance started.", rom: "Gong-yeon-i si-jak-dwaess-eo-yo." }, { kr: "공연이 너무 멋져요.", en: "The performance is so great.", rom: "Gong-yeon-i neo-mu meot-jyeo-yo." }] },
        { kr: "공예", rom: "Gong-ye", en: "Craft", tip: "How to say an activity involving skill in making things by hand in Korean?", situation: "Use this when making handmade items.", forms: { casual: "공예 (Gong-ye)", polite: "공예예요 (Gong-ye-ye-yo)" }, examples: [{ kr: "공예를 해요.", en: "I do crafts.", rom: "Gong-ye-reul hae-yo." }, { kr: "손으로 만들어요.", en: "I make things by hand.", rom: "Son-eu-ro man-deul-eo-yo." }, { kr: "공예품이 예뻐요.", en: "The crafts are pretty.", rom: "Gong-ye-pum-i ye-ppeo-yo." }] },
        { kr: "마술", rom: "Ma-sul", en: "Magic", tip: "How to refer to the power of apparently influencing the course of events by using mysterious or supernatural forces in Korean?", situation: "Use this when performing magic tricks.", forms: { casual: "마술 (Ma-sul)", polite: "마술이에요 (Ma-sul-i-e-yo)" }, examples: [{ kr: "마술을 해요.", en: "I perform magic.", rom: "Ma-sul-eul hae-yo." }, { kr: "마술이 신기해요.", en: "Magic is amazing.", rom: "Ma-sul-i sin-gi-hae-yo." }, { kr: "마술을 배워요.", en: "I learn magic.", rom: "Ma-sul-eul bae-wo-yo." }] },
        { kr: "바둑", rom: "Ba-duk", en: "Baduk", tip: "How to say a traditional board game for two players that involves placing black and white stones on a grid in Korean?", situation: "Use this when playing the board game.", forms: { casual: "바둑 (Ba-duk)", polite: "바둑이에요 (Ba-duk-i-e-yo)" }, examples: [{ kr: "바둑을 둬요.", en: "I play Baduk.", rom: "Ba-duk-eul dw-eo-yo." }, { kr: "바둑이 어려워요.", en: "Baduk is difficult.", rom: "Ba-duk-i eo-ryeo-wo-yo." }, { kr: "바둑 대결을 해요.", en: "I have a Baduk match.", rom: "Ba-duk dae-gyeol-eul hae-yo." }] },
        { kr: "장기", rom: "Jang-gi", en: "Janggi", tip: "How to refer to a traditional strategy board game often called 'Korean chess' in Korean?", situation: "Use this when playing this traditional game.", forms: { casual: "장기 (Jang-gi)", polite: "장기예요 (Jang-gi-ye-yo)" }, examples: [{ kr: "장기를 둬요.", en: "I play Janggi.", rom: "Jang-gi-reul dw-eo-yo." }, { kr: "장기 한 판 할까요?", en: "Shall we play a game of Janggi?", rom: "Jang-gi han pan hal-kka-yo?" }, { kr: "장기는 재밌어요.", en: "Janggi is fun.", rom: "Jang-gi-neun jae-miss-eo-yo." }] },
        { kr: "체스", rom: "Che-seu", en: "Chess", tip: "How to say a strategic board game played by two players on a checkered board in Korean?", situation: "Use this when playing chess.", forms: { casual: "체스 (Che-seu)", polite: "체스예요 (Che-seu-ye-yo)" }, examples: [{ kr: "체스를 둬요.", en: "I play chess.", rom: "Che-seu-reul dw-eo-yo." }, { kr: "체스를 잘해요.", en: "I am good at chess.", rom: "Che-seu-reul jal-hae-yo." }, { kr: "체스 경기를 해요.", en: "I have a chess match.", rom: "Che-seu gyeong-gi-reul hae-yo." }] },
        { kr: "카드", rom: "Ka-deu", en: "Card", tip: "How to refer to playing games with a deck of small rectangular pieces of stiff paper in Korean?", situation: "Use this when playing card games.", forms: { casual: "카드 (Ka-deu)", polite: "카드예요 (Ka-deu-ye-yo)" }, examples: [{ kr: "카드 게임을 해요.", en: "I play a card game.", rom: "Ka-deu ge-im-eul hae-yo." }, { kr: "카드를 섞어요.", en: "I shuffle the cards.", rom: "Ka-deu-reul seokk-eo-yo." }, { kr: "카드를 나눠요.", en: "I deal the cards.", rom: "Ka-deu-reul nan-wo-yo." }] }
