        { kr: "수납장", rom: "Su-nap-jang", en: "Cabinet", tip: "How to say the cupboard or storage space for keeping dishes and food in Korean?", situation: "Use this for organization.", forms: { casual: "수납장 (Su-nap-jang)", polite: "수납장이에요 (Su-nap-jang-i-e-yo)" }, examples: [{ kr: "수납장에 넣어요.", en: "I put it in the cabinet.", rom: "Su-nap-jang-e neoh-eo-yo." }, { kr: "수납장이 많아요.", en: "There are many cabinets.", rom: "Su-nap-jang-i man-a-yo." }, { kr: "수납장을 열어보세요.", en: "Please open the cabinet.", rom: "Su-nap-jang-eul yeol-eo-bo-se-yo." }] },
        { kr: "쟁반", rom: "Jaeng-ban", en: "Tray", tip: "How to refer to a flat board with raised edges used for carrying multiple dishes at once in Korean?", situation: "Use this to serve many dishes.", forms: { casual: "쟁반 (Jaeng-ban)", polite: "쟁반이에요 (Jaeng-ban-i-e-yo)" }, examples: [{ kr: "쟁반에 담아와요.", en: "I bring it on a tray.", rom: "Jaeng-ban-e dam-a-wa-yo." }, { kr: "쟁반이 무거워요.", en: "The tray is heavy.", rom: "Jaeng-ban-i mu-geo-wo-yo." }, { kr: "쟁반을 옮겨요.", en: "I carry the tray.", rom: "Jaeng-ban-eul olm-gyeo-yo." }] },
        { kr: "앞접시", rom: "Ap-jeop-si", en: "Side plate", tip: "How to say the small individual plate used for taking food from a shared main dish in Korean?", situation: "Use this when sharing food.", forms: { casual: "앞접시 (Ap-jeop-si)", polite: "앞접시예요 (Ap-jeop-si-ye-yo)" }, examples: [{ kr: "앞접시 좀 주세요.", en: "Please give me a side plate.", rom: "Ap-jeop-si jom ju-se-yo." }, { kr: "앞접시에 덜어 먹어요.", en: "I serve some on a side plate to eat.", rom: "Ap-jeop-si-e deol-eo meog-eo-yo." }, { kr: "앞접시가 더 필요해요.", en: "I need more side plates.", rom: "Ap-jeop-si-ga deo pil-yo-hae-yo." }] },
        { kr: "찬장", rom: "Chan-jang", en: "Cupboard", tip: "How to refer to the kitchen furniture used for storing tableware in Korean?", situation: "Use this to store plates.", forms: { casual: "찬장 (Chan-jang)", polite: "찬장이에요 (Chan-jang-i-e-yo)" }, examples: [{ kr: "찬장에 그릇을 넣어요.", en: "I put bowls in the cupboard.", rom: "Chan-jang-e geu-reut-eul neoh-eo-yo." }, { kr: "찬장을 닫아주세요.", en: "Please close the cupboard.", rom: "Chan-jang-eul dad-a-ju-se-yo." }, { kr: "찬장이 열려있어요.", en: "The cupboard is open.", rom: "Chan-jang-i yeol-lyeo-iss-eo-yo." }] },
        { kr: "고무장갑", rom: "Go-mu-jang-gap", en: "Rubber gloves", tip: "How to say the waterproof gloves worn to protect hands while doing dishes in Korean?", situation: "Use this to protect your hands.", forms: { casual: "고무장갑 (Go-mu-jang-gap)", polite: "고무장갑이에요 (Go-mu-jang-gap-i-e-yo)" }, examples: [{ kr: "고무장갑을 끼세요.", en: "Please put on rubber gloves.", rom: "Go-mu-jang-gap-eul kki-se-yo." }, { kr: "고무장갑이 찢어졌어요.", en: "The rubber gloves are torn.", rom: "Go-mu-jang-gap-i jji-j-eo-jyeoss-eo-yo." }, { kr: "고무장갑이 편해요.", en: "Rubber gloves are comfortable.", rom: "Go-mu-jang-gap-i pyeon-hae-yo." }] },
        { kr: "세제", rom: "Se-je", en: "Detergent", tip: "How to refer to the liquid soap used for cleaning dishes or laundry in Korean?", situation: "Use this for cleaning.", forms: { casual: "세제 (Se-je)", polite: "세제예요 (Se-je-ye-yo)" }, examples: [{ kr: "세제를 묻혀요.", en: "I put detergent on it.", rom: "Se-je-reul mud-hyeo-yo." }, { kr: "세제가 떨어졌어요.", en: "I ran out of detergent.", rom: "Se-je-ga tteol-eo-jyeoss-eo-yo." }, { kr: "세제를 조금만 쓰세요.", en: "Please use a little detergent.", rom: "Se-je-reul jo-geum-man sseu-se-yo." }] },
        { kr: "식탁보", rom: "Sik-tak-bo", en: "Tablecloth", tip: "How to say the decorative cloth used to cover the dining table in Korean?", situation: "Use this to decorate the table.", forms: { casual: "식탁보 (Sik-tak-bo)", polite: "식탁보예요 (Sik-tak-bo-ye-yo)" }, examples: [{ kr: "식탁보를 깔아요.", en: "I spread the tablecloth.", rom: "Sik-tak-bo-reul kkal-a-yo." }, { kr: "식탁보가 예뻐요.", en: "The tablecloth is pretty.", rom: "Sik-tak-bo-ga ye-ppeo-yo." }, { kr: "식탁보를 갈아주세요.", en: "Please change the tablecloth.", rom: "Sik-tak-bo-reul gal-a-ju-se-yo." }] },
        { kr: "환풍기", rom: "Hwan-pung-gi", en: "Fan", tip: "How to refer to the ventilation fan used to remove smoke and smells from the kitchen in Korean?", situation: "Use this when cooking smoky food.", forms: { casual: "환풍기 (Hwan-pung-gi)", polite: "환풍기예요 (Hwan-pung-gi-ye-yo)" }, examples: [{ kr: "환풍기를 켜세요.", en: "Please turn on the fan.", rom: "Hwan-pung-gi-reul kkhyeo-se-yo." }, { kr: "환풍기가 잘 돌아가요.", en: "The fan is working well.", rom: "Hwan-pung-gi-ga jal dol-a-ga-yo." }, { kr: "환풍기를 끄세요.", en: "Please turn off the fan.", rom: "Hwan-pung-gi-reul kkeu-se-yo." }] },
        { kr: "거품기", rom: "Geo-pum-gi", en: "Whisk", tip: "How to say the tool used for beating eggs or mixing cream in Korean?", situation: "Use this for baking.", forms: { casual: "거품기 (Geo-pum-gi)", polite: "거품기예요 (Geo-pum-gi-ye-yo)" }, examples: [{ kr: "거품기로 저어요.", en: "I whisk it.", rom: "Geo-pum-gi-ro jeo-eo-yo." }, { kr: "거품기가 필요해요.", en: "I need a whisk.", rom: "Geo-pum-gi-ga pil-yo-hae-yo." }, { kr: "거품기를 씻어요.", en: "I wash the whisk.", rom: "Geo-pum-gi-reul ssis-eo-yo." }] },
        { kr: "저울", rom: "Jeo-ul", en: "Scale", tip: "How to refer to the instrument used for measuring the weight of ingredients in Korean?", situation: "Use this when measuring ingredients.", forms: { casual: "저울 (Jeo-ul)", polite: "저울이에요 (Jeo-ul-i-e-yo)" }, examples: [{ kr: "저울에 재요.", en: "I measure it on the scale.", rom: "Jeo-ul-e jae-yo." }, { kr: "저울이 정확해요.", en: "The scale is accurate.", rom: "Jeo-ul-i jeong-hwak-hae-yo." }, { kr: "저울을 사용해 보세요.", en: "Try using the scale.", rom: "Jeo-ul-eul sa-yong-hae bo-se-yo." }] }
